using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

var builder = Host.CreateApplicationBuilder(args);

// Stdio transport uses stdout for JSON-RPC — all logging MUST go to stderr
builder.Logging.AddConsole(options =>
    options.LogToStandardErrorThreshold = LogLevel.Trace);

builder.Services.AddHttpClient("Api", client =>
{
    client.BaseAddress = new Uri("https://jsonplaceholder.typicode.com");
});

builder.Services.AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();

await builder.Build().RunAsync();

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap a REST API. Uses constructor injection for HttpClient.
/// The SDK resolves DI services automatically — they never appear in the tool schema.
/// </summary>
[McpServerToolType]
public class ApiTools(IHttpClientFactory httpClientFactory, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Get a post by its numeric ID from the API.")]
    public async Task<string> GetPost(
        [Description("The numeric ID of the post to retrieve (1-100)")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {PostId}", postId);
        var client = httpClientFactory.CreateClient("Api");
        var response = await client.GetStringAsync($"/posts/{postId}", cancellationToken);
        return response;
    }

    [McpServerTool, Description("List all posts by a specific user.")]
    public async Task<string> GetPostsByUser(
        [Description("The user ID to filter posts by")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching posts for user {UserId}", userId);
        var client = httpClientFactory.CreateClient("Api");
        var response = await client.GetStringAsync($"/posts?userId={userId}", cancellationToken);
        return response;
    }

    [McpServerTool(ReadOnly = true), Description("Search posts by keyword in the title.")]
    public async Task<string> SearchPosts(
        [Description("Keyword to search for in post titles")] string keyword,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching posts for '{Keyword}'", keyword);
        var client = httpClientFactory.CreateClient("Api");
        var json = await client.GetStringAsync("/posts", cancellationToken);
        var posts = JsonSerializer.Deserialize<JsonElement[]>(json) ?? [];

        var matches = posts
            .Where(p => p.GetProperty("title").GetString()
                ?.Contains(keyword, StringComparison.OrdinalIgnoreCase) == true)
            .ToArray();

        return JsonSerializer.Serialize(matches, new JsonSerializerOptions { WriteIndented = true });
    }
}

